// Secure gRPC server with TLS
func createSecureServer() *grpc.Server {
	// Load TLS credentials
	certFile := os.Getenv("GRPC_CERT_FILE")
	keyFile := os.Getenv("GRPC_KEY_FILE")

	if certFile == "" || keyFile == "" {
		log.Fatal("GRPC_CERT_FILE and GRPC_KEY_FILE environment variables must be set")
	}

	creds, err := credentials.NewServerTLSFromFile(certFile, keyFile)
	if err != nil {
		log.Fatalf("Failed to create TLS credentials: %v", err)
	}

	// Create gRPC server with TLS
	server := grpc.NewServer(grpc.Creds(creds))

	// Register services
	pb.RegisterUserServiceServer(server, &userService{})
	pb.RegisterOrderServiceServer(server, &orderService{})
	pb.RegisterPaymentServiceServer(server, &paymentService{})

	// Register reflection service
	reflection.Register(server)

	return server
}

func main() {
	// Create secure gRPC server
	server := createSecureServer()

	// Listen on port
	port := os.Getenv("GRPC_PORT")
	if port == "" {
		port = "50051"
	}

	lis, err := net.Listen("tcp", ":"+port)
	if err != nil {
		log.Fatalf("Failed to listen: %v", err)
	}

	log.Printf("gRPC server listening on port %s", port)

	// Start server
	if err := server.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}